------------------------------------------------------------------
function LFightStateMulti:LFightStateMulti()
    --玩法类型和阵型类型不是同一个东西，现在暂时是相等的
    self._combatType = 0 --玩法战斗类型
    self._formationType = 0 --阵型类型
    self._formationReqIndex = 0

    self._combatData = nil
    self._combatResult = nil
    self._reportId = nil

    --1 请求阵型 2 请求战斗 3 请求web  4 播放 5 结束
    self._state = 0

    self._isError = false
    self._errorPhase = 0
    self._errorStr = 0

    self._reqTime = 0

    self._timeOut = 5

    --重新次数
    self._retryCnt = 0
    self._retryMax = 1

    -- 目前只有跨服天梯用到这个字段，跨服天梯一个阵型类型，可能保存，也可能战斗
    self._isSetFormation = false

    self._resultCountDown = 3 --结算3s请求未返回的情况下，再次请求
    self._resultTimeKey = "_resultTimeKey"

    self._sid = nil                 -- 活动id
    self._isBossTowerCombat = false       -- 是否是音乐爬塔
    self._isMultiCombat = false       -- 是否是音乐爬塔多阵容

    self._timerKey = "timerKey"
end

------------------------------------------------------------------
function LFightStateMulti:IsCanReplace()
    if self._isDestroy then
        return true
    end

    --printInfoN("cur state "..tostring(self._state))
    if self._state >= LCombatStateConst.STATE_COMBAT_FINISHED then
        return true
    end

    if self._isError then
        return true
    end

    if self:CheckTimeOut() then
        return true
    end

    local noNeed = gLFightManager:IsNoNeedBackground(self._combatType)
    if noNeed then
        return true
    end


    return false
end

function LFightStateMulti:CheckTimeOut()
    if self._state == LCombatStateConst.STATE_SET_FORMATION or self._state == LCombatStateConst.STATE_REPORT_REQ or self._state == LCombatStateConst.STATE_COMBAT_REQ then
        local time = self:GetCurTime()
        local timeOut = self._timeOut
        local reqTime = self._reqTime
        if time - reqTime > timeOut then
            return true
        end
    end
    return false
end

