function LFightStateMulti:StartAfterSetFormation(combatData)
    self:SetCombatData(combatData)
    self._combatType = combatData.combatType
    self._state = LCombatStateConst.STATE_SET_FORMATION
    self:RequestCombat()
end

function LFightStateMulti:OnBossTowerSetFormationResp()
    if self._state ~= LCombatStateConst.STATE_SET_FORMATION then
        return false
    end
    self:RequestCombat()
    return true
end

function LFightStateMulti:OnSetFormationResp(pb)
    if self._state ~= LCombatStateConst.STATE_SET_FORMATION then
        return false
    end

    local reqIndex = pb.reqIndex
    local setType = pb.formationSetType
    if setType == 0 and reqIndex == self._formationReqIndex then
        self:RequestCombat()
        return true
    end

    return false
end


function LFightStateMulti:RequestCombat()
    self._combatData.isNew = true

    self._reportIsOk = false
    self._combatRespIsOk = false
    self._reqTime = self:GetCurTime()
    self._state = LCombatStateConst.STATE_COMBAT_REQ

    self:CombatReqInternal()

end

---从收到战报id 开始流程 离线战斗等
function LFightStateMulti:StartFromCombatResp(combatData)
    self._combatType = combatData.combatType
    self:SetCombatData(combatData)
    self._state = LCombatStateConst.STATE_COMBAT_REQ


    local reportIdList = {}
    for k,v in ipairs(combatData.multReportIds) do
        local okReports = self._okReports or {}
        okReports[v] = true
        self._okReports = okReports

        table.insert(reportIdList,v)
    end

    self._reportIdList = reportIdList
    self._resultKey = table.concat(reportIdList,'|')

    self:OnCombatResp(combatData)
end

function LFightStateMulti:StartFromReportId(multiReport,combatType,combatData)
    self._combatType = combatType
    self:SetCombatData(combatData)
    self._state = LCombatStateConst.STATE_COMBAT_REQ

    if not multiReport or #multiReport == 0 then
        self._isError = true
        printErrorN("report list is empty")
        if combatType then
            gModelBattle:RecordVideoBattleLife(combatType,false)
        end
        return
    end

    local reportIdList = {}
    self._waitReports = {}
    self._okReports = {}
    for k,v in ipairs(multiReport) do
        self._okReports[v] = true
        self._waitReports[v] = true
        table.insert(reportIdList,v)
    end

    self._reportIdList = reportIdList
    self._resultKey = table.concat(reportIdList,'|')

    self._combatRespIsOk = true
    self:CheckStartReqReport()

end


function LFightStateMulti:OnCombatResp(pb)
    if self._state ~= LCombatStateConst.STATE_COMBAT_REQ then
        return false
    end

    local combatType = pb.combatType
    if self._combatType ~= combatType then
        return false
    end


    self._reportIdList = {}

    self._waitReports = {}
    for k,v in ipairs(pb.multReportIds) do
        self._waitReports[v] = true

        table.insert(self._reportIdList,v)
    end
    self._resultKey = table.concat(self._reportIdList,"|")
    local serverId = pb.serverId or 0
    self._serverId = serverId > 0 and serverId or gLGameLogin:GetActualServerId()

    self._combatRespIsOk = true

    self:CheckStartReqReport()
    return true
end

function LFightStateMulti:OnCombatReportOk(pb)

    local okReports = self._okReports or {}
    okReports[pb.id] = true
    self._okReports = okReports
    self:CheckStartReqReport()

    return true
end

function LFightStateMulti:CheckStartReqReport()

    if not self._combatRespIsOk then
        return
    end

    local waitlist = self._waitReports or {}
    local okList = self._okReports or {}
    for k,v in pairs(waitlist) do
        if not okList[k] then
            return
        end
    end

    self:TryRequestWebReport()
end

function LFightStateMulti:TryRequestWebReport()
    if self:IsDestroy() then return end
    if self._state >= LCombatStateConst.STATE_REPORT_REQ then
        return
    end

    self._state = LCombatStateConst.STATE_REPORT_REQ
    self._reqTime = self:GetCurTime()
    self:RequestWebReport()
end

