function LFightStateMulti:StartReqTimer()
    self:StopReqTimer()

    if not self._timer then
        self._timer = LxTimer:New()
    end
    self:ReqReportData()
    self._timer:TimerCreate(self._timerKey,function(...)
       self:ReqReportData()
    end,0.5,false,-1)
end

