function LFightStateMulti:ReqReportData()

    if self._curIndex > #self._reportIdList then
        self:StopReqTimer()
        return
    end
    local serverId = self._serverId
    if not serverId then
        serverId = gLGameLogin:GetActualServerId()
    end

    local index = self._curIndex
    local reportId = self._reportIdList[index]
    local reportInfo =
    {
        reportId = reportId,
        combatType = self._combatType,
        serverId = serverId,
        callback = function(reportTable)
            self._reportDataList[index]= reportTable
            self:StartOneBattle(index)
        end
    }

    self._curIndex = self._curIndex + 1

    local getter = LFightReportGetter:New()
    table.insert(self._getterList,getter)
    getter:Start(reportInfo)
end

function LFightStateMulti:StartOneBattle(index)

    local isBackground = self._combatData.isBattleToBackground
    local reportData = self._reportDataList[index]
    local reportId = reportData.id

    local combatData = {}

    combatData.isBattleToBackground = isBackground or index~= 1
    combatData.combatIndex = index
    combatData.resultKey = self._resultKey
    combatData.isNew = true
    combatData.battleEndfun= self._combatData.battleEndfun
    combatData.combatType = self._combatData.combatType

    gLFightManager:StartBattle(reportId, self._combatType, combatData, reportData)
end

function LFightStateMulti:GetSid()
    return self._sid
end

function LFightStateMulti:IsBossTower()
