end

function LFightStateMulti:BattleFinish()
    self._state = LCombatStateConst.STATE_COMBAT_FINISHED
end


---结算请求
function LFightStateMulti:OnReqCombatResult()
    self._isWaitResult = true
end


function LFightStateMulti:OnRespCombatResult()
    self._isWaitResult = false
end

---重发结算请求
function LFightStateMulti:CheckResendReqResult()
    if self._isWaitResult then
        self:ReqCombatResult()
    end
end

function LFightStateMulti:ReqCombatResult()
    gModelBattle:OnCombatResultReq(self._resultKey,self._combatType)
end

function LFightStateMulti:CombatReqInternal()
    self:OnReqCombat()
    gModelBattle:OnCombatReq(self._combatData)
end

function LFightStateMulti:OnReqCombat()
    self._isWaitCombatResp = true
end

function LFightStateMulti:OnRespCombat()
    self._isWaitCombatResp = false
end

---重发战斗请求
function LFightStateMulti:CheckResendReqCombat()
    if self._isWaitCombatResp then
        self:CombatReqInternal()
    end
end

-----------------------------------------------------------------
function LFightStateMulti:IsDestroy()
    return self._isDestroy
end

function LFightStateMulti:StopReqTimer()
    if not self._timer then
        return
    end

    self._timer:TimerRemoveByKey(self._timerKey)
end

function LFightStateMulti:Destroy()

    if self._timer  then
        self._timer:Destroy()
        self._timer = nil
    end

    if self._getterList then
        for k,v in pairs(self._getterList) do
            v:Destroy()
        end
        self._getterList = nil
    end


    table.removeall(self)
    self._isDestroy = true
end
